import { useEffect, useState } from "react"
import "./newsview.css"
function Newsview() {
    const API_KEY_NEWS = process.env.REACT_APP_API_KEY_NEWS
    let [apiprompt, changeapiprompt] = useState("")
    let [apiresult, changeapires] = useState()
   useEffect(() => {
    async function getnews() {
    let backres = await fetch("http://localhost:5000/sendinterests", {
        method: "GET",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
    })
    let selectedtopics = await backres.json()
       changeapiprompt(Object.values(selectedtopics).map((item) => {
            return item.map((item2, index2) => {
               
                return  item2.toLowerCase() 
            })
            
        })[0].join('&'))
   
    
        let fetchapi = await fetch(`https://newsapi.org/v2/top-headlines?country=us&category=${apiprompt}&apiKey=${API_KEY_NEWS}`)
        let apires = await fetchapi.json()
        changeapires(apires.articles)
    }
    getnews()
    }, [])
   return (
  <>
    <div className="news-page">
      <div className="news-header">
        <h1>Latest News</h1>
        <p>Your fetched headlines</p>
      </div>

      <div className="news-grid">
        {Array.isArray(apiresult) && apiresult.length > 0 ? (
          apiresult.map((item, index) => {
            return (
              <a
                key={index}
                href={item.url}
                target="_blank"
                rel="noreferrer"
                className="news-card"
              >
                <div className="news-image-wrap">
                  <img
                    src={
                      item.urlToImage
                        ? item.urlToImage
                        : "https://via.placeholder.com/600x350?text=No+Image"
                    }
                    alt={item.title}
                    className="news-image"
                  />
                </div>

                <div className="news-content">
                  <div className="news-topline">
                    <span className="news-source">
                      {item.source?.name ? item.source.name : "Unknown Source"}
                    </span>
                    <span className="news-date">
                      {item.publishedAt
                        ? new Date(item.publishedAt).toLocaleDateString()
                        : "No date"}
                    </span>
                  </div>

                  <h2 className="news-title">{item.title}</h2>

                  <p className="news-description">
                    {item.description
                      ? item.description
                      : "No description available for this article."}
                  </p>

                  <div className="news-footer">
                    <span className="news-author">
                      {item.author ? item.author : "Unknown author"}
                    </span>
                    <span className="news-readmore">Read more →</span>
                  </div>
                </div>
              </a>
            )
          })
        ) : (
          <div className="news-empty">
            <p>No news found.</p>
          </div>
        )}
      </div>
    </div>
  </>
)
}
export default Newsview
